const app = new Howl({
  logger: true,   // log requests to stdout
  debug: true,    // verbose error overlay in dev
});

import { defineConfig, memoryCache } from "@hushkey/howl/api";

export const { defineApi, config: apiConfig } = defineConfig<State, Role>({
  roles,

  // Global rate limit (per-route can override)
  defaultRateLimit: { max: 100, windowMs: 60_000 },

  // Cache for API responses
  cache: memoryCache({ maxSize: 500 }),

  // Separate cache for rate limit counters (shared backend for multi-instance)
  rateLimitCache: redisCache(redis),

  // Auth strategy — called before every protected endpoint
  checkPermissionStrategy: async (ctx, allowedRoles) => {
    const session = ctx.cookies.get("session");
    if (!session) return ctx.json({ error: "Unauthorized" }, { status: 401 });
    const user = await verifySession(session);
    if (!user) return ctx.json({ error: "Unauthorized" }, { status: 401 });
    if (!allowedRoles.some(r => user.roles.includes(r))) {
      return ctx.json({ error: "Forbidden" }, { status: 403 });
    }
    ctx.state.userContext = user;
  },
});

// server/main.ts
import { apiConfig } from "../howl.config.ts";

app.fsApiRoutes(apiConfig);
app.fsClientRoutes();

const builder = new HowlBuilder(app, {
  root: import.meta.dirname ?? "",    // project root
  serverEntry: "./server/main.ts",    // server bundle entry
  clientEntry: "./client/pages/_app.ts", // client bundle entry
  importApp: () => app,               // for dev hot-reload
  outDir: "dist",                     // output directory
  alias: {                            // esbuild path aliases
    "@/": "./client/",
  },
  plugins: [],                        // additional esbuild plugins
});

// Tailwind v4 CSS plugin
tailwindPlugin(builder.getBuilder("default")!);

// Dev server
await builder.listen();

// Production build
await builder.build();
